func (o *UpgradeableComponent) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Cluster":
		rel, ok := retrieved.(*Cluster)
		if !ok {
			return fmt.Errorf("upgradeableComponent cannot load %T as %q", retrieved, name)
		}

		o.R.Cluster = rel

		if rel != nil {
			rel.R.UpgradeableComponents = UpgradeableComponentSlice{o}
		}
		return nil
	case "Object":
		rel, ok := retrieved.(*Object)
		if !ok {
			return fmt.Errorf("upgradeableComponent cannot load %T as %q", retrieved, name)
		}

		o.R.Object = rel

		if rel != nil {
			rel.R.UpgradeableComponents = UpgradeableComponentSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("upgradeableComponent has no relationship %q", name)
	}
}

type upgradeableComponentPreloader struct {
	Cluster func(...psql.PreloadOption) psql.Preloader
	Object  func(...psql.PreloadOption) psql.Preloader
}

func buildUpgradeableComponentPreloader() upgradeableComponentPreloader {
	return upgradeableComponentPreloader{
		Cluster: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Cluster, ClusterSlice](psql.PreloadRel{
				Name: "Cluster",
				Sides: []psql.PreloadSide{
					{
						From:        UpgradeableComponents,
						To:          Clusters,
						FromColumns: []string{"cluster_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Clusters.Columns.Names(), opts...)
		},
		Object: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Object, ObjectSlice](psql.PreloadRel{
				Name: "Object",
				Sides: []psql.PreloadSide{
					{
						From:        UpgradeableComponents,
						To:          Objects,
						FromColumns: []string{"cluster_id", "object_id"},
						ToColumns:   []string{"cluster_id", "id"},
					},
				},
			}, Objects.Columns.Names(), opts...)
		},
	}
}

