// LoadCluster loads the upgradeableComponent's Cluster into the .R struct
func (o *UpgradeableComponent) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Cluster = nil

	related, err := o.Cluster(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.UpgradeableComponents = UpgradeableComponentSlice{o}

	o.R.Cluster = related
	return nil
}

// LoadCluster loads the upgradeableComponent's Cluster into the .R struct
func (os UpgradeableComponentSlice) LoadCluster(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	clusters, err := os.Cluster(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range clusters {

			if !(o.ClusterID == rel.ID) {
				continue
			}

			rel.R.UpgradeableComponents = append(rel.R.UpgradeableComponents, o)

			o.R.Cluster = rel
			break
		}
	}

	return nil
}

// LoadObject loads the upgradeableComponent's Object into the .R struct
func (o *UpgradeableComponent) LoadObject(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Object = nil

	related, err := o.Object(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.UpgradeableComponents = UpgradeableComponentSlice{o}

	o.R.Object = related
	return nil
}

// LoadObject loads the upgradeableComponent's Object into the .R struct
func (os UpgradeableComponentSlice) LoadObject(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	objects, err := os.Object(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range objects {

			if !(o.ClusterID == rel.ClusterID) {
				continue
			}

			if !(o.ObjectID == rel.ID) {
				continue
			}

			rel.R.UpgradeableComponents = append(rel.R.UpgradeableComponents, o)

			o.R.Object = rel
			break
		}
	}

	return nil
}

type upgradeableComponentJoins[Q dialect.Joinable] struct {
	typ     string
	Cluster modAs[Q, clusterColumns]
	Object  modAs[Q, objectColumns]
}

func (j upgradeableComponentJoins[Q]) aliasedAs(alias string) upgradeableComponentJoins[Q] {
	return buildUpgradeableComponentJoins[Q](buildUpgradeableComponentColumns(alias), j.typ)
}

func buildUpgradeableComponentJoins[Q dialect.Joinable](cols upgradeableComponentColumns, typ string) upgradeableComponentJoins[Q] {
	return upgradeableComponentJoins[Q]{
		typ: typ,
		Cluster: modAs[Q, clusterColumns]{
			c: Clusters.Columns,
			f: func(to clusterColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Clusters.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ClusterID),
					))
				}

				return mods
			},
		},
		Object: modAs[Q, objectColumns]{
			c: Objects.Columns,
			f: func(to objectColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Objects.Name().As(to.Alias())).On(
						to.ClusterID.EQ(cols.ClusterID), to.ID.EQ(cols.ObjectID),
					))
				}

				return mods
			},
		},
	}
}
